#include<bits/stdc++.h>
#define int long long
using namespace std;
const int MAXA=1e5+5;
int ans=0,n,tong[MAXA];
queue<int> q1,q2;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}void f(int &t){
	if(q1.front()<q2.front())t=q1.front(),q1.pop();
	else t=q2.front(),q2.pop();
}signed main(void){
	n=read();
	for(int i=1;i<=n;++i)++tong[read()];
	for(int i=1;i<100001;++i){
		while(tong[i]--)q1.push(i);
	}for(int i=1;i<n;++i){
		int x,y;f(x);f(y);
		ans+=x+y,q2.push(x+y);
	}printf("%lld",ans);
	return false;
}
